import type {
  PluginConstructor,
  PluginOptions,
  PluginDescriptor,
  InferPluginOptions,
} from './types.ts';

/**
 * Creates a plugin descriptor with the given plugin constructor and options.
 *
 * @template T - The plugin constructor type
 * @template V - The plugin options type
 * @param plugin - The plugin constructor
 * @param options - The plugin configuration options
 * @returns A plugin descriptor containing the constructor and options
 */
export function configure<
  T extends PluginConstructor<any, any, any>,
  V extends PluginOptions = InferPluginOptions<T>,
>(plugin: T, options: V): PluginDescriptor<any, any, T> {
  return {
    plugin,
    options,
  };
}

/**
 * Creates a configurator function for a specific plugin constructor.
 *
 * @template T - The plugin constructor type
 * @param plugin - The plugin constructor to configure
 * @returns A function that takes options and returns a plugin descriptor
 */
export function configurator<T extends PluginConstructor<any, any, any>>(
  plugin: T
) {
  return (options: InferPluginOptions<T>): PluginDescriptor<any, any, T> => {
    return configure(plugin, options);
  };
}

/**
 * Normalizes a plugin constructor or descriptor into a descriptor.
 *
 * @template T - The plugin constructor type
 * @param plugin - Either a plugin constructor or a plugin descriptor
 * @returns A plugin descriptor
 */
export function descriptor<T extends PluginConstructor<any, any, any>>(
  plugin: T | PluginDescriptor<any, any, T>
): PluginDescriptor<any, any, T> {
  if (typeof plugin === 'function') {
    return {
      plugin,
      options: undefined,
    };
  }

  return plugin;
}
import {
  type CleanupFunction,
  effect,
  reactive,
  untracked,
} from '@dnd-kit/state';

import type {DragDropManager} from '../manager/index.ts';
import type {PluginOptions} from './types.ts';
import {configure} from './utilities.ts';

/**
 * Base class for plugins that extend drag and drop functionality.
 *
 * @template T - The type of drag and drop manager
 * @template U - The type of plugin options
 *
 * @remarks
 * Plugins can add new features and behaviors to the drag and drop system
 * by extending this class and implementing custom functionality.
 */
export abstract class Plugin<
  T extends DragDropManager<any, any> = DragDropManager<any, any>,
  U extends PluginOptions = PluginOptions,
> {
  /**
   * Creates a new plugin instance.
   *
   * @param manager - The drag and drop manager that owns this plugin
   * @param options - Optional configuration for the plugin
   */
  constructor(
    public manager: T,
    public options?: U
  ) {}

  /**
   * Whether the plugin instance is disabled.
   *
   * @remarks
   * This property is reactive and triggers effects when accessed.
   */
  @reactive
  public accessor disabled: boolean = false;

  /**
   * Enables a disabled plugin instance.
   *
   * @remarks
   * This method triggers effects when called.
   */
  public enable() {
    this.disabled = false;
  }

  /**
   * Disables an enabled plugin instance.
   *
   * @remarks
   * This method triggers effects when called.
   */
  public disable() {
    this.disabled = true;
  }

  /**
   * Checks if the plugin instance is disabled.
   *
   * @returns true if the plugin is disabled
   * @remarks
   * This method does not trigger effects when accessed.
   */
  public isDisabled() {
    return untracked(() => {
      return this.disabled;
    });
  }

  /**
   * Configures a plugin instance with new options.
   *
   * @param options - The new options to apply
   */
  public configure(options?: U) {
    this.options = options;
  }

  #cleanupFunctions = new Set<CleanupFunction>();

  /**
   * Registers an effect that will be cleaned up when the plugin is destroyed.
   *
   * @param callback - The effect callback to register
   * @returns A function to dispose of the effect
   */
  protected registerEffect(callback: () => void): CleanupFunction {
    const dispose = effect(callback.bind(this));

    this.#cleanupFunctions.add(dispose);

    return dispose;
  }

  /**
   * Destroys a plugin instance and cleans up its resources.
   *
   * @remarks
   * This method:
   * - Calls all registered cleanup functions
   * - Should be overridden by subclasses to clean up additional resources
   */
  public destroy() {
    this.#cleanupFunctions.forEach((cleanup) => cleanup());
  }

  /**
   * Configures a plugin constructor with options.
   *
   * @param options - The options to configure the constructor with
   * @returns The configured plugin constructor
   *
   * @remarks
   * This method is used to configure the options that the
   * plugin constructor will use to create plugin instances.
   */
  static configure(options: PluginOptions) {
    return configure(this as any, options);
  }
}

/**
 * Base class for core plugins that ship with the library.
 *
 * @template T - The type of drag and drop manager
 * @template U - The type of plugin options
 */
export class CorePlugin<
  T extends DragDropManager<any, any> = DragDropManager<any, any>,
  U extends PluginOptions = PluginOptions,
> extends Plugin<T, U> {}
import {DragDropManager} from '../manager/index.ts';
import {CorePlugin, type Plugin} from './plugin.ts';
import type {
  InferPluginOptions,
  PluginDescriptor,
  PluginConstructor,
  Plugins,
} from './types.ts';
import {descriptor} from './utilities.ts';

/**
 * Manages the registration and lifecycle of plugin instances.
 *
 * @template T - The type of drag and drop manager
 * @template W - The type of plugin constructor
 * @template U - The type of plugin instance
 */
export class PluginRegistry<
  T extends DragDropManager<any, any>,
  W extends PluginConstructor<T> = PluginConstructor<T>,
  U extends Plugin<T> = InstanceType<W>,
> {
  private instances: Map<W, U> = new Map();

  /**
   * Creates a new plugin registry.
   *
   * @param manager - The drag and drop manager that owns this registry
   */
  constructor(private manager: T) {}

  /**
   * Gets all registered plugin instances.
   *
   * @returns An array of all active plugin instances
   */
  public get values(): U[] {
    return Array.from(this.instances.values());
  }

  #previousValues: PluginConstructor<T>[] = [];

  /**
   * Sets the list of plugins to be used by the registry.
   *
   * @param entries - Array of plugin constructors or descriptors
   * @remarks
   * This method:
   * - Filters out duplicate plugins
   * - Unregisters plugins that are no longer in use
   * - Registers new plugins with their options
   */
  public set values(entries: Plugins<T>) {
    const descriptors = entries
      .map(descriptor)
      .reduce<PluginDescriptor<T>[]>((acc, descriptor) => {
        const existing = acc.find(({plugin}) => plugin === descriptor.plugin);

        if (existing) {
          // Keep the first occurrence's position, apply latest options
          existing.options = descriptor.options;
          return acc;
        }

        return [...acc, descriptor];
      }, []);
    const constructors = descriptors.map(({plugin}) => plugin);

    for (const plugin of this.#previousValues) {
      if (!constructors.includes(plugin)) {
        if (plugin.prototype instanceof CorePlugin) {
          continue;
        }

        this.unregister(plugin as W);
      }
    }

    for (const {plugin, options} of descriptors) {
      this.register(plugin as W, options as InferPluginOptions<W>);
    }

    this.#previousValues = constructors;
  }

  /**
   * Gets a plugin instance by its constructor.
   *
   * @param plugin - The plugin constructor to look up
   * @returns The plugin instance or undefined if not found
   */
  public get<X extends W>(plugin: X): InstanceType<X> | undefined {
    const instance = this.instances.get(plugin);

    return instance as any;
  }

  /**
   * Registers a new plugin instance.
   *
   * @param plugin - The plugin constructor to register
   * @param options - Optional configuration for the plugin
   * @returns The registered plugin instance
   * @remarks
   * If the plugin is already registered, its options will be updated
   * and the existing instance will be returned.
   */
  public register<X extends W>(
    plugin: X,
    options?: InferPluginOptions<X>
  ): InstanceType<X> {
    const existingInstance = this.instances.get(plugin);

    if (existingInstance) {
      if (existingInstance.options !== options) {
        existingInstance.options = options;
      }

      return existingInstance as InstanceType<X>;
    }

    const instance = new plugin(this.manager, options) as U;

    this.instances.set(plugin, instance);

    return instance as InstanceType<X>;
  }

  /**
   * Unregisters a plugin instance.
   *
   * @param plugin - The plugin constructor to unregister
   * @remarks
   * This method:
   * - Destroys the plugin instance
   * - Removes it from the registry
   */
  public unregister<X extends W>(plugin: X) {
    const instance = this.instances.get(plugin);

    if (instance) {
      instance.destroy();
      this.instances.delete(plugin);
    }
  }

  /**
   * Destroys all registered plugin instances.
   *
   * @remarks
   * This method:
   * - Calls destroy() on all plugin instances
   * - Clears the registry
   */
  public destroy() {
    for (const plugin of this.instances.values()) {
      plugin.destroy();
    }

    this.instances.clear();
  }
}
import {Collision} from './types.ts';

/**
 * Sort collisions from greatest to smallest priority
 * Collisions of equal priority are sorted from greatest to smallest value
 */
export function sortCollisions(a: Collision, b: Collision) {
  if (a.priority === b.priority) {
    if (a.type === b.type) {
      return b.value - a.value;
    }

    return b.type - a.type;
  }

  return b.priority - a.priority;
}
import {signal, untracked, type Signal, effects} from '@dnd-kit/state';
import type {Coordinates} from '@dnd-kit/geometry';

import type {DragDropManager} from '../manager/index.ts';
import type {Draggable, Droppable} from '../entities/index.ts';
import {Plugin} from '../plugins/index.ts';
import type {Collision, CollisionDetector, Collisions} from './types.ts';
import {sortCollisions} from './utilities.ts';

const DEFAULT_VALUE: Collisions = [];

/**
 * Observes and manages collision detection between draggable and droppable elements.
 *
 * @template T - The type of draggable entities
 * @template U - The type of droppable entities
 * @template V - The type of drag drop manager
