  batch,
  CleanupFunction,
  reactive,
  signal,
  type Signal,
  type Effect,
} from '@dnd-kit/state';

import {DragDropManager} from '../../manager/index.ts';
import type {Data, UniqueIdentifier} from './types.ts';

export interface Input<T extends Data = Data> {
