      this.manager.monitor.dispatch('dragend', {
        nativeEvent: args.event,
        operation: dragOperation.snapshot(),
        canceled: args.canceled ?? false,
        suspend,
      });

      if (promise) {
        promise.then(end).catch(() => dragOperation.reset());
      } else {
        end();
